def main():
    with open(DATA_PATH, "r", encoding="utf-8") as f:
        data = json.load(f)

    fixed = 0
    for sc in data["subcategories"]:
        for q in sc["questions"]:
            expl = q.get("explanation", "").strip()
            ca = q["correct_answer"]
            if (expl.startswith("Правильный пароним") or expl.startswith("Правильное слово") or len(expl) < 30):
                if ca in FIXES:
                    q["explanation"] = FIXES[ca]
                    fixed += 1
                else:
                    print(f"НЕТ ЗАМЕНЫ для: correct={ca!r}, expl={expl!r}")

    with open(DATA_PATH, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

    print(f"Исправлено: {fixed} вопросов.")


if __name__ == "__main__":
    main()
